mapper.update:
/* com.educare.edu.comn.mapper.AdminIpMapper.updateByPk */
	update t_admin_ip
	set upd_dt = #{updDt}
		,upd_id = #{updId}

		,memo = #{memo}


		,ip4 = #{ip4}


		,state = #{state}

	where idx = #{idx}

mapper.select:
/* com.educare.edu.comn.mapper.AdminIpMapper.selectAccipPageCnt */
	select count(*) from t_admin_ip where 1=1

		and state = #{state}


		and (
			ip4 like concat('%',#{srchWrd},'%') 
			or memo like concat('%',#{srchWrd},'%') 
		)

/* com.educare.edu.comn.mapper.AdminIpMapper.selectAccipPageList */
	select * from t_admin_ip where 1=1

		and state = #{state}


		and (
			ip4 like concat('%',#{srchWrd},'%') 
			or memo like concat('%',#{srchWrd},'%') 
		)	


		LIMIT #{firstIndex}, #{row}

/* com.educare.edu.comn.mapper.AdminIpMapper.selectAccipDupIp */
	select count(*) from t_admin_ip
	where ip4 = #{ip4}
	and idx != #{idx}
